import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { ArrowLeft, Star, ShoppingCart, Package, CheckCircle } from 'lucide-react';
import API from '../utils/api';
import { useCart } from '../context/CartContext';
import toast from 'react-hot-toast';

export default function ProductDetailPage() {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [selectedImage, setSelectedImage] = useState(0);
  const [selectedFlavor, setSelectedFlavor] = useState('');
  const [selectedWeight, setSelectedWeight] = useState('');
  const [qty, setQty] = useState(1);
  const { addToCart } = useCart();

  useEffect(() => {
    API.get(`/store/${id}`)
      .then(res => { setProduct(res.data); setSelectedFlavor(res.data.flavors?.[0] || ''); setSelectedWeight(res.data.weights?.[0] || ''); })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center"><div className="w-10 h-10 border-2 border-orange-500 border-t-transparent rounded-full animate-spin" /></div>;
  if (!product) return <div className="min-h-screen bg-[#0a0a0f] text-gray-400 flex items-center justify-center">Product not found</div>;

  const handleAdd = () => {
    addToCart(product, qty, selectedFlavor, selectedWeight);
    toast.success(`${product.name} added to cart!`);
  };

  return (
    <div className="min-h-screen bg-[#0a0a0f] pt-20">
      <div className="max-w-6xl mx-auto px-6 py-10">
        <Link to="/store" className="flex items-center gap-2 text-gray-400 hover:text-orange-400 mb-8 transition-colors">
          <ArrowLeft size={18} /> Back to Store
        </Link>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
          {/* Images */}
          <div>
            <div className="relative h-96 bg-gray-900 rounded-xl overflow-hidden border border-white/10 mb-3">
              {product.images?.[selectedImage] ? (
                <img src={product.images[selectedImage]} alt={product.name} className="w-full h-full object-cover" />
              ) : (
                <div className="w-full h-full flex items-center justify-center"><Package size={64} className="text-gray-700" /></div>
              )}
              {product.discountPrice && (
                <div className="absolute top-3 left-3 bg-red-500 text-white text-sm px-3 py-1 rounded-full font-bold">
                  {Math.round(((product.price - product.discountPrice) / product.price) * 100)}% OFF
                </div>
              )}
            </div>
            {product.images?.length > 1 && (
              <div className="flex gap-2">
                {product.images.map((img, i) => (
                  <button key={i} onClick={() => setSelectedImage(i)} className={`w-16 h-16 rounded-lg overflow-hidden border-2 transition-all ${selectedImage === i ? 'border-orange-500' : 'border-white/10'}`}>
                    <img src={img} alt="" className="w-full h-full object-cover" />
                  </button>
                ))}
              </div>
            )}
          </div>

          {/* Info */}
          <div>
            {product.brand && <div className="text-orange-400 text-sm font-semibold uppercase tracking-wider mb-2">{product.brand}</div>}
            <h1 className="text-white font-bold text-3xl mb-3">{product.name}</h1>

            {product.rating > 0 && (
              <div className="flex items-center gap-2 mb-4">
                {[...Array(5)].map((_, i) => (
                  <Star key={i} size={16} className={i < Math.round(product.rating) ? 'text-yellow-400 fill-yellow-400' : 'text-gray-600'} />
                ))}
                <span className="text-gray-400 text-sm">({product.reviewCount} reviews)</span>
              </div>
            )}

            <div className="flex items-center gap-3 mb-6">
              <span className="text-white font-bold text-4xl">₹{product.discountPrice || product.price}</span>
              {product.discountPrice && <span className="text-gray-500 line-through text-lg">₹{product.price}</span>}
            </div>

            <p className="text-gray-400 leading-relaxed mb-6">{product.description}</p>

            {/* Flavor */}
            {product.flavors?.length > 0 && (
              <div className="mb-4">
                <label className="text-gray-300 text-sm font-medium block mb-2">Flavor</label>
                <div className="flex gap-2 flex-wrap">
                  {product.flavors.map(f => (
                    <button key={f} onClick={() => setSelectedFlavor(f)} className={`px-3 py-1.5 rounded-lg text-sm border transition-all ${selectedFlavor === f ? 'border-orange-500 bg-orange-500/20 text-orange-400' : 'border-white/10 text-gray-400 hover:border-white/30'}`}>{f}</button>
                  ))}
                </div>
              </div>
            )}

            {/* Weight */}
            {product.weights?.length > 0 && (
              <div className="mb-6">
                <label className="text-gray-300 text-sm font-medium block mb-2">Size</label>
                <div className="flex gap-2 flex-wrap">
                  {product.weights.map(w => (
                    <button key={w} onClick={() => setSelectedWeight(w)} className={`px-3 py-1.5 rounded-lg text-sm border transition-all ${selectedWeight === w ? 'border-orange-500 bg-orange-500/20 text-orange-400' : 'border-white/10 text-gray-400 hover:border-white/30'}`}>{w}</button>
                  ))}
                </div>
              </div>
            )}

            {/* Qty + Add to cart */}
            <div className="flex items-center gap-4 mb-6">
              <div className="flex items-center gap-2 border border-white/10 rounded-lg">
                <button onClick={() => setQty(q => Math.max(1, q - 1))} className="px-3 py-2 text-gray-400 hover:text-white">−</button>
                <span className="text-white font-bold px-3">{qty}</span>
                <button onClick={() => setQty(q => q + 1)} className="px-3 py-2 text-gray-400 hover:text-white">+</button>
              </div>
              <span className="text-gray-500 text-sm">{product.stock > 0 ? `${product.stock} in stock` : 'Out of stock'}</span>
            </div>

            {product.stock > 0 ? (
              <button onClick={handleAdd} className="btn-fire w-full flex items-center justify-center gap-2 text-base py-4">
                <ShoppingCart size={20} /> Add to Cart
              </button>
            ) : (
              <div className="w-full text-center text-red-400 py-4 border border-red-500/20 rounded-lg">Out of Stock</div>
            )}
          </div>
        </div>

        {/* Reviews */}
        {product.reviews?.length > 0 && (
          <div className="mt-14">
            <h2 className="text-white font-bold text-2xl mb-6">Customer Reviews</h2>
            <div className="grid gap-4">
              {product.reviews.map((r, i) => (
                <div key={i} className="glass rounded-xl p-5">
                  <div className="flex items-center justify-between mb-2">
                    <div className="font-semibold text-white">{r.name}</div>
                    <div className="flex gap-1">
                      {[...Array(5)].map((_, j) => <Star key={j} size={14} className={j < r.rating ? 'text-yellow-400 fill-yellow-400' : 'text-gray-600'} />)}
                    </div>
                  </div>
                  <p className="text-gray-400 text-sm">{r.comment}</p>
                  <p className="text-gray-600 text-xs mt-2">{new Date(r.date).toLocaleDateString()}</p>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
